import "core-js/modules/esnext.iterator.map.js";
import * as echarts from 'echarts';
import { getAnalysisSummary } from '@/api/analysis';
export default {
  name: 'AnalysisCategorySales',
  data() {
    return {
      loading: true,
      errorMsg: '',
      chartInstance: null,
      chartData: []
    };
  },
  async mounted() {
    try {
      const res = await getAnalysisSummary();
      const categorySales = res.data.data.category_sales || [];
      this.chartData = categorySales.map(item => ({
        name: item.category,
        value: item.sales
      }));
      this.$nextTick(() => {
        this.initChart();
      });
    } catch (error) {
      if (error.response) {
        this.errorMsg = `请求失败，状态码：${error.response.status}`;
      } else if (error.request) {
        this.errorMsg = '请求已发出，但后端没有正常响应';
      } else {
        this.errorMsg = `请求错误：${error.message}`;
      }
      console.error(error);
    } finally {
      this.loading = false;
    }
  },
  methods: {
    initChart() {
      if (!this.$refs.chartRef) return;
      this.chartInstance = echarts.init(this.$refs.chartRef);
      const option = {
        tooltip: {
          trigger: 'item'
        },
        legend: {
          orient: 'vertical',
          left: 'left'
        },
        series: [{
          name: '分类销量',
          type: 'pie',
          radius: ['45%', '70%'],
          avoidLabelOverlap: false,
          itemStyle: {
            borderRadius: 8,
            borderColor: '#fff',
            borderWidth: 2
          },
          label: {
            show: true,
            formatter: '{b}: {c} ({d}%)'
          },
          emphasis: {
            label: {
              show: true,
              fontSize: 16,
              fontWeight: 'bold'
            }
          },
          labelLine: {
            show: true
          },
          data: this.chartData
        }]
      };
      this.chartInstance.setOption(option);
    }
  },
  beforeDestroy() {
    if (this.chartInstance) {
      this.chartInstance.dispose();
      this.chartInstance = null;
    }
  }
};
